// ============================================
// montarPromptGroq v11.0 — IA NARRA, JS ESTRUTURA
// ============================================

let input = $input.first().json;
if (Array.isArray(input)) input = input[0];
if (input && !input.cards && input.json?.cards) input = input.json;
if (input && !input.cards) {
  for (const key of Object.keys(input)) {
    const v = input[key];
    if (v && typeof v === 'object' && !Array.isArray(v) && v.cards) { input = v; break; }
    if (Array.isArray(v) && v[0]?.cards) { input = v[0]; break; }
  }
}
if (!input?.cards) {
  throw new Error('Input invalido. Keys: ' + JSON.stringify(Object.keys($input.first().json || {})));
}

const projeto = input.projeto_info || { nome: 'Projeto' };
const todosCards = input.cards || [];
const resumo = input.resumo || {};
const sprints = input.sprints_identificadas || [];
const meta = input.metadados_coleta || {};

// === HELPERS ===
function fh(h) {
  if (!h) return '0h';
  const hr = Math.floor(h), mn = Math.round((h - hr) * 60);
  return mn === 0 ? `${hr}h` : `${hr}h${mn}min`;
}

function fn(f) {
  if (!f) return 'Sem Fase';
  return typeof f === 'string' ? f : (f.nome || 'Sem Fase');
}

function getFaseFlag(info, flag) {
  if (!info || typeof info !== 'object') return false;
  return info[flag] === true;
}

function tituloLimpo(t) {
  if (!t) return '';
  return t.replace(/^[\s✅❌🔄⚠️📌💡🎯🧱]+/, '').trim();
}

// Resumir descrição: primeiros N caracteres, corta na última frase completa
function resumirDescricao(desc, maxChars = 200) {
  if (!desc) return 'Sem descrição disponível.';
  let texto = desc.trim();
  if (texto.length <= maxChars) return texto;

  // Corta no maxChars e volta até o último ponto/ponto-e-vírgula
  let cortado = texto.substring(0, maxChars);
  const ultimoPonto = Math.max(cortado.lastIndexOf('.'), cortado.lastIndexOf(';'), cortado.lastIndexOf('!'));
  if (ultimoPonto > maxChars * 0.4) {
    cortado = cortado.substring(0, ultimoPonto + 1);
  } else {
    cortado = cortado.trim() + '...';
  }
  return cortado;
}

// === CLASSIFICAÇÃO ===
function classificar(card) {
  const info = card.fase_atual_nome;
  const nome = fn(info).toLowerCase();
  if (getFaseFlag(info, 'conclusao')) return 'concluidos';
  if (nome.includes('concluído') || nome.includes('concluido')) return 'concluidos';
  if (nome.includes('cancelado')) return 'cancelados';
  if (nome.includes('andamento')) return 'em_andamento';
  if (getFaseFlag(info, 'testes')) return 'em_testes';
  if (nome.includes('teste')) return 'em_testes';
  if (nome.includes('deploy')) return 'aguardando_deploy';
  if (nome.includes('sprint')) return 'sprint_atual';
  if (nome.includes('backlog') || nome.includes('fila') ||
      nome.includes('standby') || nome.includes('pendente')) return 'pendentes';
  return 'outros';
}

const grupos = {
  concluidos: [], cancelados: [], em_andamento: [],
  em_testes: [], aguardando_deploy: [], sprint_atual: [],
  pendentes: [], outros: []
};
todosCards.forEach(c => { const s = classificar(c); c._st = s; grupos[s].push(c); });

const emTrabalho = [...grupos.sprint_atual, ...grupos.em_andamento, ...grupos.aguardando_deploy, ...grupos.em_testes];
const somaGrupos = Object.values(grupos).reduce((s, a) => s + a.length, 0);

// === PERÍODO ===
const dataColeta = meta.data_coleta || new Date().toISOString();
const dataColetaObj = new Date(dataColeta);
const diasPeriodo = meta.periodo_analise_dias || 15;
const dataInicio = new Date(dataColetaObj);
dataInicio.setDate(dataInicio.getDate() - diasPeriodo);
const pIni = dataInicio.toLocaleDateString('pt-BR');
const pFim = dataColetaObj.toLocaleDateString('pt-BR');

// === IDENTIFICAR SPRINT ATUAL vs HISTÓRICA ===
// Sprints do período = iniciaram dentro dos últimos diasPeriodo*2 dias
const limiteSprintRecente = new Date(dataColetaObj);
limiteSprintRecente.setDate(limiteSprintRecente.getDate() - (diasPeriodo * 2));

function isSprintRecente(card) {
  if (!card.sprint_info?.periodo?.inicio) return false;
  const inicioSprint = new Date(card.sprint_info.periodo.inicio);
  return inicioSprint >= limiteSprintRecente;
}

// === EQUIPES REAIS (quem trabalhou, não só responsável) ===
function equipesReais(card) {
  const equipes = new Set();

  // 1. Equipes dos responsáveis com horas > 0
  if (card.times && Array.isArray(card.times)) {
    card.times.forEach(t => {
      if (t.equipe && t.equipe !== 'Externo' && t.equipe !== 'A definir' && t.equipe !== 'Outros') {
        // Se tem horas lançadas, é equipe ativa
        if (t.horas_periodo > 0) {
          equipes.add(t.equipe);
        }
      }
    });
  }

  // 2. Fallback: equipes_envolvidas (se ninguém teve horas)
  if (equipes.size === 0 && card.equipes_envolvidas) {
    card.equipes_envolvidas
      .filter(e => e !== 'Gestão') // Remove gestão do fallback
      .forEach(e => equipes.add(e));
  }

  // 3. Se ainda vazio, usa equipes_envolvidas com gestão
  if (equipes.size === 0 && card.equipes_envolvidas) {
    card.equipes_envolvidas.forEach(e => equipes.add(e));
  }

  return [...equipes];
}

// === MÉTRICAS ===
function diasAtraso(dataDesejada, dataRef) {
  if (!dataDesejada) return null;
  const deadline = new Date(dataDesejada);
  const ref = new Date(dataRef);
  const diff = Math.floor((ref - deadline) / (1000 * 60 * 60 * 24));
  return diff > 0 ? diff : null;
}

const horasEquipe = Object.entries(resumo.horas?.horas_por_equipe || {})
  .sort((a, b) => b[1] - a[1])
  .map(([e, h]) => `${e}: ${fh(h)}`)
  .join(', ');

const totalReaberturas = todosCards.reduce((s, c) => s + (c.metricas_deteccao?.reaberturas || 0), 0);
const totalReprovacoes = todosCards.reduce((s, c) => s + (c.metricas_deteccao?.reprovacoes || 0), 0);
const horasEntregasPeriodo = grupos.concluidos.reduce((s, c) => s + (c.tempo_trabalhado_horas || 0), 0);

// Cards com alertas críticos
const cardsComAlertasCriticos = new Set();
const alertasCriticosDetalhados = [];
todosCards.forEach(c => {
  (c.anomalias || []).forEach(a => {
    if (a.severidade === 'ALTA' || a.severidade === 'CRITICA') {
      cardsComAlertasCriticos.add(c.id);
      alertasCriticosDetalhados.push({
        id: c.id,
        titulo: tituloLimpo(c.titulo),
        msg: a.mensagem,
        tipo: a.tipo,
        acao: a.acao
      });
    }
  });
});

// Deadlines estourados (ativos, não cancelados/concluídos)
const deadlines = [];
emTrabalho.forEach(c => {
  const atraso = diasAtraso(c.data_desejada, dataColeta);
  if (atraso) deadlines.push({ id: c.id, titulo: tituloLimpo(c.titulo), dias: atraso });
});

// Cards com reaberturas (detalhar quais)
const cardsComReaberturas = todosCards
  .filter(c => (c.metricas_deteccao?.reaberturas || 0) > 0)
  .map(c => ({ id: c.id, titulo: tituloLimpo(c.titulo), reaberturas: c.metricas_deteccao.reaberturas }));

// Cards com reprovações (detalhar quais)
const cardsComReprovacoes = todosCards
  .filter(c => (c.metricas_deteccao?.reprovacoes || 0) > 0)
  .map(c => ({ id: c.id, titulo: tituloLimpo(c.titulo), reprovacoes: c.metricas_deteccao.reprovacoes }));

// === AGRUPAR POR SPRINT ===
const sprintOrdem = sprints.map(s => s.nome);
function sortSprints(keys) {
  return keys.sort((a, b) => {
    const ia = sprintOrdem.indexOf(a), ib = sprintOrdem.indexOf(b);
    if (ia === -1 && ib === -1) return 0;
    if (ia === -1) return 1;
    if (ib === -1) return -1;
    return ia - ib;
  });
}

// ============================================
// MONTAR DADOS ESTRUTURADOS PARA A IA
// ============================================

let dados = '';

// --- CONTEXTO ---
dados += `PROJETO: ${projeto.nome} (ID: ${projeto.id})\n`;
dados += `PERÍODO DE ANÁLISE: ${pIni} a ${pFim} (${diasPeriodo} dias)\n`;
dados += `DATA DA COLETA: ${dataColetaObj.toLocaleDateString('pt-BR')}\n\n`;

// --- NÚMEROS DO PERÍODO ---
dados += `=== NÚMEROS DO PERÍODO ===\n`;
dados += `Total de cards ativos: ${todosCards.length}\n`;
dados += `Entregas concluídas: ${grupos.concluidos.length}\n`;
dados += `Em testes: ${grupos.em_testes.length}\n`;
dados += `Em andamento: ${grupos.em_andamento.length}\n`;
dados += `Em sprint (aguardando início): ${grupos.sprint_atual.length}\n`;
dados += `Aguardando deploy: ${grupos.aguardando_deploy.length}\n`;
dados += `Pendentes: ${grupos.pendentes.length}\n`;
dados += `Cancelados: ${grupos.cancelados.length}\n`;
dados += `Cards com alertas críticos: ${cardsComAlertasCriticos.size}\n`;
dados += `Horas trabalhadas no período: ${fh(resumo.horas?.total_horas_periodo || 0)}\n`;
dados += `Distribuição por equipe: ${horasEquipe}\n`;
dados += `Pessoas ativas: ${resumo.horas?.total_pessoas_ativas || 0}\n`;
dados += `Horas acumuladas nas entregas: ${fh(horasEntregasPeriodo)}\n`;
dados += `Reaberturas no período: ${totalReaberturas}\n`;
dados += `Reprovações no período: ${totalReprovacoes}\n\n`;

// --- ENTREGAS CONCLUÍDAS ---
dados += `=== ENTREGAS CONCLUÍDAS (${grupos.concluidos.length}) ===\n`;
grupos.concluidos.forEach(c => {
  const eq = equipesReais(c);
  const estouro = c.orcado_horas > 0
    ? Math.round(((c.tempo_trabalhado_horas - c.orcado_horas) / c.orcado_horas) * 100)
    : null;

  dados += `\n- Card #${c.id}: "${tituloLimpo(c.titulo)}"\n`;
  dados += `  O que faz: ${resumirDescricao(c.descricao_limpa)}\n`;
  dados += `  Equipes: ${eq.length ? eq.join(', ') : 'Não identificada'}\n`;
  dados += `  Tempo trabalhado: ${fh(c.tempo_trabalhado_horas)}`;
  if (c.orcado_horas > 0) {
    dados += ` (orçado: ${fh(c.orcado_horas)}`;
    if (estouro !== null && estouro !== 0) {
      dados += `, ${estouro > 0 ? 'estouro de ' + estouro + '%' : Math.abs(estouro) + '% abaixo'}`;
    }
    dados += `)`;
  }
  dados += `\n`;
  if (c.pontos_totais) dados += `  Complexidade: ${c.pontos_totais} pontos\n`;
  dados += `  Concluído em: ${c.data_conclusao || 'N/A'}\n`;
  if (c.sprint_identificada) dados += `  Sprint: ${c.sprint_identificada}\n`;

  // Trajetória resumida
  if (c.logs_fase && c.logs_fase.length > 0) {
    const trajetoria = c.logs_fase.map(l => l.para).join(' → ');
    dados += `  Trajetória: ${trajetoria}\n`;
  }

  // Anomalias
  if (c.anomalias && c.anomalias.length > 0) {
    dados += `  Alertas: ${c.anomalias.map(a => a.mensagem).join('; ')}\n`;
  }
});
dados += '\n';

// --- EM TESTES ---
if (grupos.em_testes.length > 0) {
  dados += `=== EM TESTES (${grupos.em_testes.length}) ===\n`;
  dados += `Observação: cards nesta fase aguardam validação/homologação antes de serem concluídos.\n`;
  grupos.em_testes.forEach(c => {
    const eq = equipesReais(c);
    const atraso = diasAtraso(c.data_desejada, dataColeta);

    dados += `\n- Card #${c.id}: "${tituloLimpo(c.titulo)}"\n`;
    dados += `  O que faz: ${resumirDescricao(c.descricao_limpa, 150)}\n`;
    dados += `  Equipes: ${eq.length ? eq.join(', ') : 'Não identificada'}\n`;
    dados += `  Tempo trabalhado: ${fh(c.tempo_trabalhado_horas)}`;
    if (c.orcado_horas > 0) dados += ` (orçado: ${fh(c.orcado_horas)})`;
    dados += `\n`;
    if (c.pontos_totais) dados += `  Complexidade: ${c.pontos_totais} pontos\n`;
    if (c.dias_na_fase_atual != null) dados += `  Dias em testes: ${c.dias_na_fase_atual}\n`;
    if (atraso) dados += `  ⚠ Deadline estourado há ${atraso} dias\n`;
    if (c.sprint_identificada && isSprintRecente(c)) dados += `  Sprint: ${c.sprint_identificada}\n`;
    if (!isSprintRecente(c) && c.sprint_identificada) dados += `  Nota: card legado, sprint original era ${c.sprint_identificada}\n`;

    if (c.anomalias && c.anomalias.length > 0) {
      dados += `  Alertas: ${c.anomalias.map(a => `${a.mensagem} → ${a.acao}`).join('; ')}\n`;
    }
  });
  dados += '\n';
}

// --- EM ANDAMENTO ---
if (grupos.em_andamento.length > 0) {
  dados += `=== EM ANDAMENTO (${grupos.em_andamento.length}) ===\n`;
  grupos.em_andamento.forEach(c => {
    const eq = equipesReais(c);
    const atraso = diasAtraso(c.data_desejada, dataColeta);

    dados += `\n- Card #${c.id}: "${tituloLimpo(c.titulo)}"\n`;
    dados += `  O que faz: ${resumirDescricao(c.descricao_limpa, 150)}\n`;
    dados += `  Equipes: ${eq.length ? eq.join(', ') : 'Não identificada'}\n`;
    dados += `  Tempo trabalhado: ${fh(c.tempo_trabalhado_horas)}`;
    if (c.orcado_horas > 0) dados += ` (orçado: ${fh(c.orcado_horas)})`;
    dados += `\n`;
    if (c.dias_na_fase_atual != null) dados += `  Dias em andamento: ${c.dias_na_fase_atual}\n`;
    if (atraso) dados += `  ⚠ Deadline estourado há ${atraso} dias\n`;
    if (c.sprint_identificada) dados += `  Sprint: ${c.sprint_identificada}\n`;

    if (c.logs_fase && c.logs_fase.length > 0) {
      const ultimoMov = c.logs_fase[c.logs_fase.length - 1];
      dados += `  Última movimentação: ${ultimoMov.frase} (${new Date(ultimoMov.data).toLocaleDateString('pt-BR')})\n`;
    }

    if (c.anomalias && c.anomalias.length > 0) {
      dados += `  Alertas: ${c.anomalias.map(a => a.mensagem).join('; ')}\n`;
    }
  });
  dados += '\n';
}

// --- SPRINT ATUAL (aguardando início) ---
if (grupos.sprint_atual.length > 0) {
  dados += `=== NA SPRINT ATUAL - AGUARDANDO INÍCIO (${grupos.sprint_atual.length}) ===\n`;
  grupos.sprint_atual.forEach(c => {
    const eq = equipesReais(c);
    dados += `\n- Card #${c.id}: "${tituloLimpo(c.titulo)}"\n`;
    dados += `  O que faz: ${resumirDescricao(c.descricao_limpa, 120)}\n`;
    dados += `  Equipes: ${eq.length ? eq.join(', ') : 'Não identificada'}\n`;
    if (c.orcado_horas > 0) dados += `  Orçado: ${fh(c.orcado_horas)}\n`;
    if (c.pontos_totais) dados += `  Complexidade: ${c.pontos_totais} pontos\n`;
  });
  dados += '\n';
}

// --- AGUARDANDO DEPLOY ---
if (grupos.aguardando_deploy.length > 0) {
  dados += `=== AGUARDANDO DEPLOY (${grupos.aguardando_deploy.length}) ===\n`;
  grupos.aguardando_deploy.forEach(c => {
    dados += `- Card #${c.id}: "${tituloLimpo(c.titulo)}" - ${fh(c.tempo_trabalhado_horas)}\n`;
  });
  dados += '\n';
}

// --- PENDENTES ---
if (grupos.pendentes.length > 0) {
  dados += `=== PENDENTES (${grupos.pendentes.length}) ===\n`;
  grupos.pendentes.forEach(c => {
    const fase = fn(c.fase_atual_nome);
    dados += `\n- Card #${c.id}: "${tituloLimpo(c.titulo)}"\n`;
    dados += `  Fase: ${fase}\n`;
    dados += `  O que faz: ${resumirDescricao(c.descricao_limpa, 100)}\n`;
    if (c.dias_na_fase_atual != null) dados += `  Dias nesta fase: ${c.dias_na_fase_atual}\n`;
  });
  dados += '\n';
}

// --- CANCELADOS ---
if (grupos.cancelados.length > 0) {
  dados += `=== CANCELADOS (${grupos.cancelados.length}) ===\n`;
  grupos.cancelados.forEach(c => {
    dados += `\n- Card #${c.id}: "${tituloLimpo(c.titulo)}"\n`;
    dados += `  O que fazia: ${resumirDescricao(c.descricao_limpa, 100)}\n`;
    if (c.logs_fase && c.logs_fase.length > 0) {
      const trajetoria = c.logs_fase.map(l => `${l.de} → ${l.para}`).join(', ');
      dados += `  Trajetória antes do cancelamento: ${trajetoria}\n`;
    }
    if (c.anomalias && c.anomalias.length > 0) {
      dados += `  Observações: ${c.anomalias.map(a => a.mensagem).join('; ')}\n`;
    }
  });
  dados += '\n';
}

// --- ALERTAS CRÍTICOS ---
if (alertasCriticosDetalhados.length > 0) {
  dados += `=== ALERTAS CRÍTICOS (${cardsComAlertasCriticos.size} cards, ${alertasCriticosDetalhados.length} alertas) ===\n`;

  // Agrupar por card para dar contexto
  const alertasPorCard = {};
  alertasCriticosDetalhados.forEach(a => {
    if (!alertasPorCard[a.id]) alertasPorCard[a.id] = { titulo: a.titulo, alertas: [] };
    alertasPorCard[a.id].alertas.push({ msg: a.msg, tipo: a.tipo, acao: a.acao });
  });

  for (const [id, info] of Object.entries(alertasPorCard)) {
    dados += `\n- Card #${id}: "${info.titulo}"\n`;
    info.alertas.forEach(a => {
      dados += `  • ${a.msg}\n`;
      dados += `    Ação sugerida: ${a.acao}\n`;
    });
  }
  dados += '\n';
}

// --- RETRABALHO ---
if (cardsComReaberturas.length > 0 || cardsComReprovacoes.length > 0) {
  dados += `=== INDICADORES DE RETRABALHO ===\n`;
  if (cardsComReaberturas.length > 0) {
    dados += `Reaberturas:\n`;
    cardsComReaberturas.forEach(c => {
      dados += `- Card #${c.id} "${c.titulo}": reaberto ${c.reaberturas}x após conclusão\n`;
    });
  }
  if (cardsComReprovacoes.length > 0) {
    dados += `Reprovações em testes:\n`;
    cardsComReprovacoes.forEach(c => {
      dados += `- Card #${c.id} "${c.titulo}": reprovado ${c.reprovacoes}x\n`;
    });
  }
  dados += '\n';
}

// --- DEADLINES ---
if (deadlines.length > 0) {
  dados += `=== DEADLINES ESTOURADOS (${deadlines.length}) ===\n`;
  deadlines
    .sort((a, b) => b.dias - a.dias)
    .forEach(d => {
      dados += `- Card #${d.id} "${d.titulo}": ${d.dias} dias de atraso\n`;
    });
  dados += '\n';
}

// ============================================
// PROMPT — IA GERA NARRATIVA A PARTIR DOS DADOS
// ============================================

const prompt = `Você é um analista de projetos de software experiente. Sua tarefa é gerar um **acompanhamento semanal** do projeto para envio ao coordenador e ao cliente.

## Instruções

Gere um relatório em Markdown com as seguintes seções:

### 1. Resumo Executivo (3-5 frases)
- Síntese do que aconteceu no período
- Destaque as entregas mais relevantes com contexto (o que foi entregue e por que importa)
- Mencione as horas totais do período e a distribuição por equipe
- Se houver alertas críticos, mencione brevemente

### 2. Entregas Concluídas
- Para cada entrega, escreva 1-2 frases explicando O QUE foi entregue (não só o título)
- Inclua o número do card, o tempo trabalhado e as equipes envolvidas
- Se houve estouro de orçamento ou complexidade alta, mencione como contexto, não como crítica
- Agrupe por sprint quando fizer sentido

### 3. Em Desenvolvimento
- Agrupe por status: Em Testes, Em Andamento, Aguardando na Sprint
- Para cards em testes, destaque há quantos dias aguardam validação
- Para cards com deadline estourado, sinalize
- Mencione brevemente o que cada card faz
- Se houver cards legados (de sprints antigas), agrupe-os separadamente com contexto

### 4. Pendentes e Bloqueios
- Liste cards pendentes/aguardando cliente
- Cards cancelados com breve explicação do porquê (se possível inferir dos logs)

### 5. Alertas e Riscos
- Alertas críticos com ação sugerida
- Deadlines estourados ordenados por gravidade
- Indicadores de retrabalho (reaberturas, reprovações) COM CONTEXTO — diga de qual card e o que aconteceu, não só números soltos

### 6. Análise e Recomendações
- Identifique PADRÕES nos dados (ex: gargalo em testes, concentração de complexidade, etc.)
- Sugira 2-3 ações concretas baseadas nos dados
- Destaque o que foi positivo no período

## Regras de Estilo
- Tom profissional mas acessível — o leitor pode ser um coordenador técnico ou um cliente não-técnico
- Português do Brasil com acentuação correta
- Use negrito para destaques importantes
- NÃO invente dados — use APENAS o que está nos dados abaixo
- NÃO use emojis
- Quando citar um card, use o formato: "nome do card (#ID)"
- Diferencie claramente "horas acumuladas no card" de "horas trabalhadas no período"
- Se um dado não está disponível, não invente — omita ou diga "não disponível"

