// FUNÇÃO: Converter Markdown para HTML
// ============================================
function markdownParaHTML(texto) {
  if (!texto) return '<p>Relatório não gerado</p>';

  let html = texto
    // Headers (ordem importa!)
    .replace(/^#### (.+)$/gm, '</p><h5 class="md-h5">$1</h5><p>')
    .replace(/^### (.+)$/gm, '</p><h4 class="md-h4">$1</h4><p>')
    .replace(/^## (.+)$/gm, '</p><h3 class="md-h3">$1</h3><p>')
    // Bold
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    // Listas
    .replace(/^- (.+)$/gm, '<li>$1</li>')
    // Parágrafos
    .replace(/\n\n/g, '</p><p>')
    // Quebras simples dentro de parágrafos
    .replace(/\n/g, '<br>');

  // Limpa tags vazias
  html = html.replace(/<p><\/p>/g, '');
  html = html.replace(/<p><h/g, '<h');
  html = html.replace(/<\/h([1-6])><\/p>/g, '</h$1>');

  return `<p>${html}</p>`;
}

